struct Wallet {
    let privateKey: P256.Signing.PrivateKey
    let publicKey: P256.Signing.PublicKey
    let address: String

    var privateKeyData: Data {
        privateKey.rawRepresentation
    }

    init() throws {
        let privateKey = P256.Signing.PrivateKey()
        self.privateKey = privateKey
        self.publicKey = privateKey.publicKey
        self.address = Wallet.ethereumAddress(from: privateKey.publicKey.rawRepresentation)
    }

    init?(privateKeyData: Data) throws {
        guard let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: privateKeyData) else { return nil }
        self.privateKey = privateKey
        self.publicKey = privateKey.publicKey
        self.address = Wallet.ethereumAddress(from: privateKey.publicKey.rawRepresentation)
    }

    static func create() throws -> Wallet {
        try Wallet()
    }

    func sign(transaction: Transaction) throws -> SignedTransaction {
        let hash = transaction.hashToSign()
        let signature = try privateKey.signature(for: hash)
        let der = signature.derRepresentation
        let raw = transaction.serialized().appending(der)
        return SignedTransaction(rawTransaction: raw, rawHex: raw.hexString)
    }

    private static func ethereumAddress(from publicKeyData: Data) -> String {
        let data = publicKeyData
        let sha = SHA256.hash(data: data)
        let addressData = Data(sha).suffix(20)
        return "0x" + addressData.hexString
    }
}

struct Transaction {
    let nonce: UInt64
    let to: String
    let value: Decimal
    let gasLimit: UInt64
    let gasPrice: UInt64
    let data: Data
    let chainId: UInt64

    func serialized() -> Data {
        var result = Data()
        result.append(nonce.bigEndianData)
        result.append(to.data(using: .utf8) ?? Data())
        result.append(value.nsDecimalNumber.uint64Value.bigEndianData)
        result.append(gasLimit.bigEndianData)
        result.append(gasPrice.bigEndianData)
        result.append(data)
        result.append(chainId.bigEndianData)
        return result
    }

    func hashToSign() -> Data {
        let serialized = serialized()
        let hash = SHA256.hash(data: serialized)
        return Data(hash)
    }
}

struct SignedTransaction {
