    let rawHex: String
}

final class BlockchainService {
    static let shared = BlockchainService()
    private init() {}

    func fetchETHBalance(address: String) async throws -> Double {
        guard let url = URL(string: "https://cloudflare-eth.com") else { throw URLError(.badURL) }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_getBalance",
            "params": [address, "latest"],
            "id": 1
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: body)
        let (data, _) = try await URLSession.shared.data(for: request)
        let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
        let result = json?["result"] as? String ?? "0x0"
        return BlockchainService.hexWeiToEth(result)
    }

    func broadcast(rawTransactionHex: String) async throws -> String {
        guard let url = URL(string: "https://cloudflare-eth.com") else { throw URLError(.badURL) }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": "eth_sendRawTransaction",
            "params": [rawTransactionHex.hasPrefix("0x") ? rawTransactionHex : "0x\(rawTransactionHex)"],
            "id": 1
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: body)
        let (data, _) = try await URLSession.shared.data(for: request)
        let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
        if let error = json?["error"] as? [String: Any], let message = error["message"] as? String {
            throw NSError(domain: "BlockchainService", code: -1, userInfo: [NSLocalizedDescriptionKey: message])
        }
        return json?["result"] as? String ?? ""
    }

    private static func hexWeiToEth(_ hex: String) -> Double {
        let cleaned = hex.replacingOccurrences(of: "0x", with: "")
        let decimal = Decimal(string: String(Int(cleaned, radix: 16) ?? 0)) ?? 0
        return NSDecimalNumber(decimal: decimal / 1_000_000_000_000_000_000).doubleValue
    }
}

final class KeychainService {
    func storePrivateKey(_ data: Data, account: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else { throw NSError(domain: "Keychain", code: Int(status)) }
    }

    func storeData(_ data: Data, account: String) throws {
        try storePrivateKey(data, account: account)
    }

    func readData(account: String) throws -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
}

extension UInt64 {
    var bigEndianData: Data {
        var value = self.bigEndian
        return Data(bytes: &value, count: MemoryLayout<UInt64>.size)
    }
}

extension Data {
    var hexString: String { map { String(format: "%02x", $0) }.joined() }
}

extension Decimal {
    var nsDecimalNumber: NSDecimalNumber { NSDecimalNumber(decimal: self) }
}